// Some portions generated by Claude Code
package org.eclipse.rdf4j.query.algebra;

import static org.junit.jupiter.api.Assertions.assertSame;

import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.Test;

public class NAryValueOperatorTest {

	/**
	 * {@link QueryModelNode#replaceWith(QueryModelNode)} delegates to the parent's {@code replaceChildNode}, which must
	 * leave the tree consistent: the replacement's parent reference has to point at the operator. A missing parent
	 * reference breaks later {@code replaceWith} calls on the replacement and trips the optimizer pipeline's
	 * parent-reference checker.
	 */
	@Test
	public void replaceChildNodeSetsParentOnReplacement() {
		Var original = Var.of("original");
		Coalesce coalesce = new Coalesce(new ArrayList<>(List.of(original, Var.of("other"))));

		Var replacement = Var.of("replacement");
		original.replaceWith(replacement);

		assertSame(coalesce, replacement.getParentNode());
		assertSame(replacement, coalesce.getArguments().get(0));
	}
}
